<div class="page-title"><h2>Inventario</h2></div><div class="grid two"><div class="card"><h3>Crear categoría</h3><form method="post" action="/inventory/categories" class="form"><?= csrf_field() ?><label>Nombre<input name="name" required></label><label>Descripción<textarea name="description"></textarea></label><button class="btn">Guardar categoría</button></form></div><div class="card"><h3>Crear producto</h3><form method="post" action="/inventory/products" class="form two-cols"><?= csrf_field() ?><label>Categoría<select name="category_id" required><?php foreach($categories as $category): ?><option value="<?= $category['id'] ?>"><?= e($category['name']) ?></option><?php endforeach; ?></select></label><label>SKU<input name="sku" required></label><label>Nombre<input name="name" required></label><label>Stock mínimo<input type="number" step="1" min="0" name="stock_min" value="0"></label><label>Costo<input type="number" step="0.01" name="cost" value="0"></label><label>Precio<input type="number" step="0.01" name="price" value="0"></label><label>Moneda<select name="currency_code"><option value="<?= e(base_currency()) ?>"><?= e(base_currency()) ?></option><option value="<?= e(secondary_currency()) ?>"><?= e(secondary_currency()) ?></option></select></label><label>Almacén inicial<select name="warehouse_id"><option value="">--</option><?php foreach($warehouses as $warehouse): ?><option value="<?= $warehouse['id'] ?>"><?= e($warehouse['name']) ?></option><?php endforeach; ?></select></label><label>Stock inicial<input type="number" step="1" min="0" name="initial_stock" value="0"></label><label class="col-span-2">Descripción<textarea name="description"></textarea></label><button class="btn col-span-2">Guardar producto</button></form></div></div><div class="card"><h3>Productos</h3><table class="table"><thead><tr><th>ID</th><th>SKU</th><th>Producto</th><th>Categoría</th><th>Stock</th><th>Mínimo</th><th>Costo</th><th>Precio</th><th>Moneda</th></tr></thead><tbody><?php foreach($products as $row): ?><tr><td><?= $row['id'] ?></td><td><?= e($row['sku']) ?></td><td><?= e($row['name']) ?></td><td><?= e($row['category_name']) ?></td><td><?= money($row['stock']) ?></td><td><?= money($row['stock_min']) ?></td><td><?= money($row['cost']) ?></td><td><?= money($row['price']) ?></td><td><?= e($row['currency_code']) ?></td></tr><?php endforeach; ?></tbody></table></div>
